CREATE TABLE `SalesVisitReport` (`id` VARCHAR(191) NOT NULL, `appointmentId` VARCHAR(191) NOT NULL, `authorUserId` VARCHAR(191) NOT NULL, `html` LONGTEXT NOT NULL, `closedAt` DATETIME(3) NOT NULL, `commandId` VARCHAR(191) NOT NULL, `externalId` VARCHAR(191) NULL, `sourceVersion` VARCHAR(191) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, PRIMARY KEY (`id`), UNIQUE INDEX `SalesVisitReport_appointmentId_key` (`appointmentId`), UNIQUE INDEX `SalesVisitReport_commandId_key` (`commandId`), INDEX `SalesVisitReport_authorUserId_closedAt_idx` (`authorUserId`, `closedAt`), CONSTRAINT `SalesVisitReport_appointmentId_fkey` FOREIGN KEY (`appointmentId`) REFERENCES `SalesAppointment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT `SalesVisitReport_authorUserId_fkey` FOREIGN KEY (`authorUserId`) REFERENCES `User` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE `SalesVisitReportAddendum` (`id` VARCHAR(191) NOT NULL, `reportId` VARCHAR(191) NOT NULL, `authorUserId` VARCHAR(191) NOT NULL, `reason` VARCHAR(191) NOT NULL, `html` LONGTEXT NOT NULL, `commandId` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `SalesVisitReportAddendum_commandId_key` (`commandId`), INDEX `SalesVisitReportAddendum_reportId_createdAt_idx` (`reportId`, `createdAt`), INDEX `SalesVisitReportAddendum_authorUserId_createdAt_idx` (`authorUserId`, `createdAt`), CONSTRAINT `SalesVisitReportAddendum_reportId_fkey` FOREIGN KEY (`reportId`) REFERENCES `SalesVisitReport` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT `SalesVisitReportAddendum_authorUserId_fkey` FOREIGN KEY (`authorUserId`) REFERENCES `User` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE `SalesLead` (`id` VARCHAR(191) NOT NULL, `appointmentId` VARCHAR(191) NOT NULL, `actorUserId` VARCHAR(191) NOT NULL, `title` VARCHAR(191) NOT NULL, `description` TEXT NULL, `commandId` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `SalesLead_commandId_key` (`commandId`), INDEX `SalesLead_appointmentId_createdAt_idx` (`appointmentId`, `createdAt`), CONSTRAINT `SalesLead_appointmentId_fkey` FOREIGN KEY (`appointmentId`) REFERENCES `SalesAppointment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT `SalesLead_actorUserId_fkey` FOREIGN KEY (`actorUserId`) REFERENCES `User` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE `SalesFollowUp` (`id` VARCHAR(191) NOT NULL, `appointmentId` VARCHAR(191) NOT NULL, `actorUserId` VARCHAR(191) NOT NULL, `type` VARCHAR(191) NOT NULL, `description` TEXT NOT NULL, `commandId` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `SalesFollowUp_commandId_key` (`commandId`), INDEX `SalesFollowUp_appointmentId_createdAt_idx` (`appointmentId`, `createdAt`), CONSTRAINT `SalesFollowUp_appointmentId_fkey` FOREIGN KEY (`appointmentId`) REFERENCES `SalesAppointment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT `SalesFollowUp_actorUserId_fkey` FOREIGN KEY (`actorUserId`) REFERENCES `User` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE `SalesReference` (`id` VARCHAR(191) NOT NULL, `appointmentId` VARCHAR(191) NOT NULL, `actorUserId` VARCHAR(191) NOT NULL, `proposedName` VARCHAR(191) NOT NULL, `contactName` VARCHAR(191) NULL, `email` VARCHAR(191) NULL, `phone` VARCHAR(191) NULL, `comment` TEXT NULL, `commandId` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `SalesReference_commandId_key` (`commandId`), INDEX `SalesReference_appointmentId_createdAt_idx` (`appointmentId`, `createdAt`), CONSTRAINT `SalesReference_appointmentId_fkey` FOREIGN KEY (`appointmentId`) REFERENCES `SalesAppointment` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT `SalesReference_actorUserId_fkey` FOREIGN KEY (`actorUserId`) REFERENCES `User` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE `SalesDayClosure` (`id` VARCHAR(191) NOT NULL, `representativeUserId` VARCHAR(191) NOT NULL, `businessDate` DATE NOT NULL, `closedAt` DATETIME(3) NOT NULL, `commandId` VARCHAR(191) NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, PRIMARY KEY (`id`), UNIQUE INDEX `SalesDayClosure_commandId_key` (`commandId`), UNIQUE INDEX `SalesDayClosure_representativeUserId_businessDate_key` (`representativeUserId`, `businessDate`), INDEX `SalesDayClosure_businessDate_closedAt_idx` (`businessDate`, `closedAt`), CONSTRAINT `SalesDayClosure_representativeUserId_fkey` FOREIGN KEY (`representativeUserId`) REFERENCES `User` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE);
